// ── AI Analysis ──
async function analyzeImages(filePaths, mimeType) {
  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) throw new Error('ANTHROPIC_API_KEY not set');

  const isImage = mimeType.startsWith('image/');
  const pageWord = filePaths.length > 1 ? `${filePaths.length}-page document` : 'document';

  const prompt = `Analyze this ${pageWord} and return ONLY a valid JSON object (no markdown, no backticks):
{
  "title": "short descriptive title max 60 chars",
  "category": "bill|tax|tax_receipt|notice|appointment|receipt|insurance|legal|financial|other",
  "priority": "urgent|high|normal|low",
  "sender": "org or person name or null",
  "amount": "dollar amount e.g. $45.00 or null",
  "dueDate": "YYYY-MM-DD or null",
  "appointmentDate": "YYYY-MM-DD or null",
  "summary": "2-3 sentence plain English summary covering all pages",
  "actionRequired": "specific action needed or null",
  "keyDetails": ["3 to 5 key facts across all pages"],
  "taxYear": "4-digit year or null"
}`;

  // Build content blocks — one image/doc per page
  const contentBlocks = [];
  for (const fp of filePaths) {
    const data = fs.readFileSync(fp).toString('base64');
    if (isImage) {
      contentBlocks.push({ type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data } });
    } else {
      contentBlocks.push({ type: 'document', source: { type: 'base64', media_type: 'application/pdf', data } });
    }
  }
  contentBlocks.push({ type: 'text', text: prompt });

  const r = await axios.post('https://api.anthropic.com/v1/messages',
    { model: 'claude-opus-4-5', max_tokens: 1024, messages: [{ role: 'user', content: contentBlocks }] },
    { headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' } }
  );
  const text = r.data.content.find(b => b.type === 'text')?.text || '{}';
  return JSON.parse(text.replace(/```json|```/g, '').trim());
}

// ── API: backup status & manual trigger ──
app.get('/api/backup', (req, res) => {
  const backups = listBackups();
  res.json({ backups, currentDocCount: readDocs().length });
});

app.post('/api/backup', (req, res) => {
  try {
    runBackup();
    const backups = listBackups();
    res.json({ success: true, message: 'Backup created', backups });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// ── API: restore from backup ──
app.post('/api/backup/restore/:filename', (req, res) => {
  try {
    const filename = req.params.filename;
    // Security: only allow our own backup filenames
    if (!filename.match(/^documents-[\d\-T]+\.json$/)) {
      return res.status(400).json({ error: 'Invalid filename' });
    }
    const backupPath = path.join(BACKUP_DIR, filename);
    if (!fs.existsSync(backupPath)) return res.status(404).json({ error: 'Backup not found' });

    // Save current state as a backup before restoring
    runBackup();

    const backupData = fs.readFileSync(backupPath, 'utf8');
    const docs = JSON.parse(backupData);
    fs.writeFileSync(META_FILE, backupData, 'utf8');
    console.log(`[Backup] Restored ${docs.length} docs from ${filename}`);
    res.json({ success: true, docCount: docs.length, message: `Restored ${docs.length} documents` });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// ── Catch-all ──
app.get('*', (req, res) => {
  res.setHeader('Content-Type', 'text/html');
  res.send(Buffer.from(ASSETS['/'].b64, 'base64'));
});

app.listen(PORT, () => {
  console.log(`Mail Desk running on port ${PORT}`);
  // Run first backup shortly after startup, then every hour
  setTimeout(runBackup, 15000);
  setInterval(runBackup, 60 * 60 * 1000);
});

// ── AUTO-BACKUP SYSTEM ──
const BACKUP_DIR  = path.join(DATA_DIR, 'backups');
const MAX_BACKUPS = 30;   // keep 30 hourly snapshots (~30 hours of history)

function ensureBackupDir() {
  if (!fs.existsSync(BACKUP_DIR)) fs.mkdirSync(BACKUP_DIR, { recursive: true });
}

function runBackup() {
  try {
    ensureBackupDir();
    if (!fs.existsSync(META_FILE)) return;
    const docs = readDocs();
    if (!docs.length) return;   // nothing to back up yet

    const stamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const backupFile = path.join(BACKUP_DIR, `documents-${stamp}.json`);
    fs.writeFileSync(backupFile, JSON.stringify(docs, null, 2), 'utf8');
    console.log(`[Backup] Saved ${docs.length} docs → ${backupFile}`);

    // Prune old backups — keep only the newest MAX_BACKUPS
    pruneBackups();
  } catch (e) {
    console.error('[Backup] Failed:', e.message);
  }
}

function pruneBackups() {
  try {
    const files = fs.readdirSync(BACKUP_DIR)
      .filter(f => f.startsWith('documents-') && f.endsWith('.json'))
      .sort();   // lexicographic = chronological because of ISO format
    if (files.length > MAX_BACKUPS) {
      files.slice(0, files.length - MAX_BACKUPS).forEach(f => {
        fs.unlinkSync(path.join(BACKUP_DIR, f));
      });
    }
  } catch (e) {
    console.error('[Backup] Prune failed:', e.message);
  }
}

function listBackups() {
  try {
    ensureBackupDir();
    return fs.readdirSync(BACKUP_DIR)
      .filter(f => f.startsWith('documents-') && f.endsWith('.json'))
      .sort().reverse()
      .map(f => {
        const stat = fs.statSync(path.join(BACKUP_DIR, f));
        const docs = JSON.parse(fs.readFileSync(path.join(BACKUP_DIR, f), 'utf8'));
        return { filename: f, size: stat.size, docCount: docs.length, createdAt: stat.mtime.toISOString() };
      });
  } catch (e) { return []; }
}
